import { IToolHandler, ToolResponse } from "@massa-ai/shared";
import { SearchController } from "../controllers/search-controller.js";
import { serializeToolResponse } from "./serialize.js";

interface SearchProjectParams {
  query: string;
  projectId: string;
  maxResults?: number;
  minScore?: number;
}

export class SearchProjectTool implements IToolHandler {
  name = "search_project";
  description = "Search for code in an indexed project";

  async handle(params: unknown): Promise<ToolResponse> {
    const { query, projectId } = params as SearchProjectParams;
    const controller = new SearchController();
    const result = await controller.search({ query, projectId });
    return serializeToolResponse(result);
  }
}
